// for loop: start at 1; run while i <= 5; add 1 each time
for (let i = 1; i <= 5; i++) {
  console.log('Count:', i);
}
// Expected output:
// Count: 1
// Count: 2
// Count: 3
// Count: 4
// Count: 5

// Same logic with a while loop
let j = 1;
while (j <= 5) {
  console.log('While count:', j);
  j++;
}
